--            c = utf8_decode(p, &p_next);
-+            c = utf8_decode_len(p, s->buf_end - p, &p_next);
-             if (p_next == p + 1)
-                 goto invalid_utf8;
-             p = p_next;
-@@ -21470,7 +21470,7 @@ static __exception int next_token(JSParseState *s)
